								)
							).toBe(fiber)
						end
					)

					generateIsFiberMounted(true)
					generateIsMounted(true)
				end
			)

			local fiberFlags = {
				placement = Placement,
				hydrating = Hydrating,
			}
			-- ROBLOX FIXME Luau: need to fix CLI-56768 to remove any casts
