				)
				jestExpect(Scheduler).toFlushAndYieldThrough({
					"A...E",
					"Sync effect",
				})
				jestExpect(ReactNoop.getChildren()).toEqual({ span("A...E") })
			end)
		end).toErrorDev({--[[no errors]]
		})

		jestExpect(Scheduler).toHaveYielded({
			"Did destroy [A....]",
			"Did create [A...E]",
		})

		jestExpect(function()
			act(function()
