		jestExpect(ReactNoop.getChildren("portalContainer")).toEqual({})

		ReactNoop.render(React.createElement(Foo))
		jestExpect(Scheduler).toFlushWithoutYielding()
		jestExpect(ReactNoop.getChildren()).toEqual({})
		jestExpect(ReactNoop.getChildren("portalContainer")).toEqual({
			div(),
			span("Hello"),
			text("World"),
		})

		ReactNoop.render(nil)
		jestExpect(Scheduler).toFlushWithoutYielding()
		jestExpect(ReactNoop.getChildren()).toEqual({})
		jestExpect(ReactNoop.getChildren("portalContainer")).toEqual({})
	end)

