				"Promise resolved [new value]",
			})
			jestExpect(Scheduler).toFlushAndYield({
				"new value",
			})
			-- ROBLOX FIXME: this last render doesn't flush, so this fails because it receives nil
			jestExpect(root).toMatchRenderedOutput("new value")
		end
	)
